export async function createAccount(client, data) {
  await ensureSchema(client);
  const doc = { ...data };
  await client.query('INSERT INTO accounts (account_id, doc) VALUES ($1, $2) RETURNING doc', [doc.accountId, JSON.stringify(doc)]);
